from azure.ai.projects.models import (
    AgentThread,
    ThreadRun,
    RequiredAction,
    SubmitToolOutputsAction,
    ToolOutput
)
from vex_sdk import VexValidationError, PolicyViolation

def execute_tool(tool_name: str, tool_args: dict) -> dict:
    """Your actual tool implementation."""
    # Replace with real tool logic
    if tool_name == "get_employee_data":
        return {"name": "Jane Doe", "role": "Engineer", "ssn": "123-45-6789"}
    return {"result": "tool output"}

def process_run_with_vex_validation(
    agent_client,
    vex: VexClient,
    thread_id: str,
    run_id: str
) -> ThreadRun:
    """Process an agent run, validating all tool outputs through Vex."""

    agents = agent_client.agents

    while True:
        run = agents.get_run(thread_id=thread_id, run_id=run_id)

        if run.status == "requires_action":
            required_action: SubmitToolOutputsAction = run.required_action
            tool_outputs = []

            for tool_call in required_action.submit_tool_outputs.tool_calls:
                tool_name = tool_call.function.name
                tool_args = json.loads(tool_call.function.arguments)

                # Execute the actual tool
                raw_output = execute_tool(tool_name, tool_args)

                # Validate output through Vex before returning to agent
                try:
                    validated_output = vex.validate_tool_output(
                        tool_name=tool_name,
                        tool_args=tool_args,
                        tool_output=raw_output,
                        context={"thread_id": thread_id, "run_id": run_id}
                    )
                    output_str = json.dumps(validated_output.sanitized_output)
                except PolicyViolation as e:
                    # Return policy-safe error message instead of violating data
                    output_str = json.dumps({
                        "error": "Tool output blocked by enterprise policy",
                        "policy_id": e.policy_id,
                        "safe_message": e.user_safe_message
                    })
                    vex.log_violation(e, thread_id=thread_id, run_id=run_id)

                tool_outputs.append(
                    ToolOutput(tool_call_id=tool_call.id, output=output_str)
                )

            agents.submit_tool_outputs_to_run(
                thread_id=thread_id,
                run_id=run_id,
                tool_outputs=tool_outputs
            )

        elif run.status in ("completed", "failed", "cancelled", "expired"):
            return run

        import time
        time.sleep(0.5)

