import { AIProjectClient } from "@azure/ai-projects";
import { DefaultAzureCredential } from "@azure/identity";
import { VexClient, ThreadHealthResult, DegradationStrategy } from "vex-sdk";

const azureClient = new AIProjectClient(
  process.env.AZURE_SUBSCRIPTION_ID!,
  process.env.AZURE_RESOURCE_GROUP!,
  process.env.AZURE_AI_PROJECT_NAME!,
  new DefaultAzureCredential()
);

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  threadMonitoring: {
    tokenWarningThreshold: 0.75,   // Warn at 75% of context window
    tokenCriticalThreshold: 0.90,  // Degrade gracefully at 90%
    modelContextWindow: 128000,    // GPT-4o context window
    degradationStrategy: DegradationStrategy.SUMMARIZE_AND_PRUNE
  }
});

async function createMessageWithTokenGuard(
  threadId: string,
  userMessage: string,
  agentId: string
): Promise<{ runId: string; degraded: boolean; warning?: string }> {
  const agents = azureClient.agents;

  // Check thread health before adding new message
  const threadHealth: ThreadHealthResult = await vex.checkThreadHealth({
    threadId,
    pendingMessageTokenEstimate: vex.estimateTokens(userMessage),
    fetchThreadMessages: async () => {
      const msgs = await agents.listMessages(threadId);
      return msgs.data.map(m => ({
        role: m.role,
        content: m.content
          .filter(c => c.type === "text")
          .map(c => (c as any).text.value)
          .join(" ")
      }));
    }
  });

  let actualThreadId = threadId;
  let degraded = false;
  let warning: string | undefined;

  if (threadHealth.status === "critical") {
    // Summarize thread and create continuation thread
    const summary = await vex.summarizeThread({
      threadId,
      messages: threadHealth.messages,
      preserveSystemInstructions: true,
      summaryMaxTokens: 2000
    });

    // Create new thread with summary as context
    const newThread = await agents.createThread();
    await agents.createMessage(newThread.id, {
      role: "user",
      content: `[Conversation context summary]: ${summary.summaryText}`
    });

    actualThreadId = newThread.id;
    degraded = true;
    warning = `Thread ${threadId} exceeded 90% token capacity. Continued in new thread ${newThread.id} with summarized context.`;

    await vex.logDegradationEvent({
      originalThreadId: threadId,
      continuationThreadId: newThread.id,
      tokensAtDegradation: threadHealth.currentTokenCount,
      strategy: "summarize_and_prune"
    });

  } else if (threadHealth.status === "warning") {
    warning = `Thread at ${Math.round(threadHealth.utilizationPercent * 100)}% token capacity. Consider starting a new conversation soon.`;
  }

  // Add user message to (potentially new) thread
  await agents.createMessage(actualThreadId, {
    role: "user",
    content: userMessage
  });

  // Create and return run
  const run = await agents.createRun(actualThreadId, agentId);

  return {
    runId: run.id,
    degraded,
    warning
  };
}

// Usage
const result = await createMessageWithTokenGuard(
  "thread_abc123",
  "Summarize the latest Azure security advisories and compare with our current configuration.",
  "asst_xyz789"
);

if (result.degraded) {
  console.warn(`Thread degradation occurred: ${result.warning}`);
}
console.log(`Run created: ${result.runId}, degraded: ${result.degraded}`);
